import { useState } from 'react'
import { useNavigate } from 'react-router'
import { ArrowLeft, ArrowRight, Check } from 'lucide-react'
import { cn } from '@/lib/utils'
import { useProjects } from '@/hooks/use-projects'

const steps = ['Project Info', 'Platform', 'Build Config', 'Source']

const softwareOptions = [
  { value: 'paper', label: 'Paper', description: 'High performance Minecraft fork' },
  { value: 'spigot', label: 'Spigot', description: 'Popular Bukkit fork' },
  { value: 'bukkit', label: 'Bukkit', description: 'Original modding API' },
  { value: 'velocity', label: 'Velocity', description: 'Modern proxy server' },
  { value: 'bungeecord', label: 'BungeeCord', description: 'Legacy proxy server' },
]

const javaVersions = ['21', '17', '11', '8']
const compilers = [
  { value: 'gradle', label: 'Gradle', description: 'Modern build tool (recommended)' },
  { value: 'maven', label: 'Maven', description: 'Traditional build tool' },
]

export default function NewProjectPage() {
  const navigate = useNavigate()
  const { createProject, isCreating } = useProjects()
  const [step, setStep] = useState(0)
  const [error, setError] = useState<string | null>(null)
  const [form, setForm] = useState({
    name: '',
    software: 'paper',
    language: 'java' as 'java' | 'kotlin',
    javaVersion: '21',
    compiler: 'gradle',
    source: 'blank' as 'blank' | 'zip' | 'github',
  })

  const canProceed = () => {
    switch (step) {
      case 0: return form.name.trim().length >= 2
      case 1: return !!form.software
      case 2: return !!form.compiler && !!form.javaVersion
      case 3: return !!form.source
      default: return false
    }
  }

  const handleCreate = async () => {
    setError(null)
    try {
      const project = await createProject({
        name: form.name.trim(),
        software: form.software,
        language: form.language,
        javaVersion: form.javaVersion,
        compiler: form.compiler as 'maven' | 'gradle',
      })
      navigate(`/workspace/${project.id}`)
    } catch (err: unknown) {
      const message = err !== null && typeof err === 'object' && 'message' in err
        ? String(err.message)
        : 'Failed to create project'
      setError(message)
    }
  }

  return (
    <div className="mx-auto max-w-2xl px-4 py-8 sm:px-6">
      <button
        onClick={() => navigate('/dashboard')}
        className="mb-6 inline-flex items-center gap-2 text-sm text-text-muted hover:text-text"
      >
        <ArrowLeft className="h-4 w-4" />
        Back to projects
      </button>

      <h1 className="text-2xl font-bold tracking-tight text-text">Create New Project</h1>
      <p className="mt-1 text-sm text-text-muted">Set up your Minecraft plugin project</p>

      {/* Step indicators */}
      <div className="mt-8 flex items-center gap-2">
        {steps.map((label, i) => (
          <div key={label} className="flex flex-1 items-center gap-2">
            <div
              className={cn(
                'flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-xs font-medium transition-colors',
                i < step
                  ? 'bg-primary text-primary-foreground'
                  : i === step
                    ? 'border-2 border-primary text-primary'
                    : 'border border-border text-text-dim'
              )}
            >
              {i < step ? <Check className="h-4 w-4" /> : i + 1}
            </div>
            <span className={cn(
              'hidden text-xs sm:block',
              i === step ? 'text-text' : 'text-text-dim'
            )}>
              {label}
            </span>
            {i < steps.length - 1 && (
              <div className={cn(
                'h-px flex-1',
                i < step ? 'bg-primary' : 'bg-border'
              )} />
            )}
          </div>
        ))}
      </div>

      {/* Step content */}
      <div className="mt-8 rounded-xl border border-border bg-surface p-6">
        {step === 0 && (
          <div className="space-y-4">
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Project Name</label>
              <input
                type="text"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-text placeholder:text-text-dim focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                placeholder="MyAwesomePlugin"
              />
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Project Type</label>
              <div className="rounded-lg border border-primary bg-primary/5 px-4 py-3">
                <p className="text-sm font-medium text-text">Minecraft Plugin</p>
                <p className="text-xs text-text-muted">Server-side plugin for Minecraft Java Edition</p>
              </div>
            </div>
          </div>
        )}

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Server Software</label>
              <div className="space-y-2">
                {softwareOptions.map((sw) => (
                  <button
                    key={sw.value}
                    onClick={() => setForm({ ...form, software: sw.value })}
                    className={cn(
                      'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                      form.software === sw.value
                        ? 'border-primary bg-primary/5'
                        : 'border-border hover:border-border-bright hover:bg-surface-hover'
                    )}
                  >
                    <div className={cn(
                      'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                      form.software === sw.value
                        ? 'border-primary bg-primary'
                        : 'border-border'
                    )}>
                      {form.software === sw.value && <div className="h-2 w-2 rounded-full bg-white" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-text">{sw.label}</p>
                      <p className="text-xs text-text-muted">{sw.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Language</label>
              <div className="flex gap-3">
                {(['java', 'kotlin'] as const).map((lang) => (
                  <button
                    key={lang}
                    onClick={() => setForm({ ...form, language: lang })}
                    className={cn(
                      'flex-1 rounded-lg border px-4 py-3 text-sm font-medium transition-colors',
                      form.language === lang
                        ? 'border-primary bg-primary/5 text-text'
                        : 'border-border text-text-muted hover:border-border-bright'
                    )}
                  >
                    {lang.charAt(0).toUpperCase() + lang.slice(1)}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-medium text-text">Java Version</label>
              <select
                value={form.javaVersion}
                onChange={(e) => setForm({ ...form, javaVersion: e.target.value })}
                className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-text focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              >
                {javaVersions.map((v) => (
                  <option key={v} value={v}>Java {v}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="mb-3 block text-sm font-medium text-text">Build Tool</label>
              <div className="space-y-2">
                {compilers.map((c) => (
                  <button
                    key={c.value}
                    onClick={() => setForm({ ...form, compiler: c.value })}
                    className={cn(
                      'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                      form.compiler === c.value
                        ? 'border-primary bg-primary/5'
                        : 'border-border hover:border-border-bright hover:bg-surface-hover'
                    )}
                  >
                    <div className={cn(
                      'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                      form.compiler === c.value
                        ? 'border-primary bg-primary'
                        : 'border-border'
                    )}>
                      {form.compiler === c.value && <div className="h-2 w-2 rounded-full bg-white" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-text">{c.label}</p>
                      <p className="text-xs text-text-muted">{c.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-4">
            <label className="mb-3 block text-sm font-medium text-text">Project Source</label>
            <div className="space-y-2">
              {[
                { value: 'blank' as const, label: 'Blank Project', description: 'Start from scratch with a clean template' },
                { value: 'zip' as const, label: 'Upload ZIP', description: 'Import from a ZIP archive (coming soon)' },
                { value: 'github' as const, label: 'GitHub Repository', description: 'Clone from a GitHub repo (coming soon)' },
              ].map((opt) => (
                <button
                  key={opt.value}
                  onClick={() => opt.value === 'blank' && setForm({ ...form, source: opt.value })}
                  disabled={opt.value !== 'blank'}
                  className={cn(
                    'flex w-full items-center gap-3 rounded-lg border px-4 py-3 text-left transition-colors',
                    form.source === opt.value
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:border-border-bright hover:bg-surface-hover',
                    opt.value !== 'blank' && 'cursor-not-allowed opacity-50'
                  )}
                >
                  <div className={cn(
                    'flex h-4 w-4 shrink-0 items-center justify-center rounded-full border',
                    form.source === opt.value
                      ? 'border-primary bg-primary'
                      : 'border-border'
                  )}>
                    {form.source === opt.value && <div className="h-2 w-2 rounded-full bg-white" />}
                  </div>
                  <div>
                    <p className="text-sm font-medium text-text">{opt.label}</p>
                    <p className="text-xs text-text-muted">{opt.description}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 rounded-lg border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
          {error}
        </div>
      )}

      {/* Navigation */}
      <div className="mt-6 flex items-center justify-between">
        <button
          onClick={() => setStep(step - 1)}
          disabled={step === 0}
          className="inline-flex items-center gap-2 rounded-lg border border-border px-4 py-2 text-sm text-text-muted transition-colors hover:bg-surface disabled:opacity-50"
        >
          <ArrowLeft className="h-4 w-4" />
          Previous
        </button>
        {step < steps.length - 1 ? (
          <button
            onClick={() => setStep(step + 1)}
            disabled={!canProceed()}
            className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            Next
            <ArrowRight className="h-4 w-4" />
          </button>
        ) : (
          <button
            onClick={handleCreate}
            disabled={!canProceed() || isCreating}
            className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary-hover disabled:opacity-50"
          >
            {isCreating ? 'Creating...' : 'Create Project'}
          </button>
        )}
      </div>
    </div>
  )
}

import Fastify from 'fastify'
import fastifyStatic from '@fastify/static'
import path from 'path'
import { fileURLToPath } from 'url'
import { env } from './env.js'
import corsPlugin from './plugins/cors.js'
import cookiePlugin from './plugins/cookie.js'
import websocketPlugin from './plugins/websocket.js'
import { authRoutes } from './routes/auth.js'
import { healthRoutes } from './routes/health.js'
import { projectRoutes } from './routes/projects.js'
import { agentRoutes } from './routes/agents.js'
import { adminRoutes } from './routes/admin.js'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const app = Fastify({
  logger: {
    level: env.NODE_ENV === 'production' ? 'info' : 'debug',
    transport: env.NODE_ENV !== 'production'
      ? { target: 'pino-pretty', options: { translateTime: 'HH:MM:ss', ignore: 'pid,hostname' } }
      : undefined,
  },
})

// Plugins
await app.register(corsPlugin)
await app.register(cookiePlugin)
await app.register(websocketPlugin)

// Routes
await app.register(authRoutes)
await app.register(healthRoutes)
await app.register(projectRoutes)
await app.register(agentRoutes)
await app.register(adminRoutes)

// Serve built client in production
const clientDist = path.resolve(__dirname, '../../client/dist')
await app.register(fastifyStatic, {
  root: clientDist,
  prefix: '/',
  wildcard: false,
})

// SPA fallback — serve index.html for non-API routes
app.setNotFoundHandler(async (request, reply) => {
  if (request.url.startsWith('/api')) {
    return reply.status(404).send({ message: 'Not found', statusCode: 404 })
  }
  return reply.sendFile('index.html')
})

// Start
try {
  await app.listen({ port: env.PORT, host: env.HOST })
  console.log(`Server running at http://${env.HOST}:${env.PORT}`)
} catch (err) {
  app.log.error(err)
  process.exit(1)
}

import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import { eq, and, desc } from 'drizzle-orm'
import { db } from '../db/index.js'
import { projects } from '../db/schema/projects.js'
import { authMiddleware } from '../middleware/auth.js'

const createProjectSchema = z.object({
  name: z.string().min(2).max(128),
  description: z.string().max(1000).optional(),
  software: z.string().max(32).default('paper'),
  language: z.enum(['java', 'kotlin']).default('java'),
  javaVersion: z.string().max(8).default('21'),
  compiler: z.enum(['maven', 'gradle']).default('gradle'),
})

const updateProjectSchema = z.object({
  name: z.string().min(2).max(128).optional(),
  description: z.string().max(1000).nullable().optional(),
  status: z.enum(['active', 'archived']).optional(),
  software: z.string().max(32).optional(),
  language: z.enum(['java', 'kotlin']).optional(),
  javaVersion: z.string().max(8).optional(),
  compiler: z.enum(['maven', 'gradle']).optional(),
})

export async function projectRoutes(app: FastifyInstance) {
  // List projects for current user
  app.get('/api/projects', { preHandler: [authMiddleware] }, async (request) => {
    const userProjects = await db
      .select()
      .from(projects)
      .where(eq(projects.userId, request.user!.id))
      .orderBy(desc(projects.updatedAt))

    return userProjects
  })

  // Get single project
  app.get('/api/projects/:id', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { id } = request.params as { id: string }

    const [project] = await db
      .select()
      .from(projects)
      .where(and(eq(projects.id, id), eq(projects.userId, request.user!.id)))
      .limit(1)

    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    return project
  })

  // Create project
  app.post('/api/projects', { preHandler: [authMiddleware] }, async (request, reply) => {
    const parsed = createProjectSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const [project] = await db
      .insert(projects)
      .values({
        userId: request.user!.id,
        ...parsed.data,
      })
      .returning()

    return reply.status(201).send(project)
  })

  // Update project
  app.patch('/api/projects/:id', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { id } = request.params as { id: string }
    const parsed = updateProjectSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const [existing] = await db
      .select({ id: projects.id })
      .from(projects)
      .where(and(eq(projects.id, id), eq(projects.userId, request.user!.id)))
      .limit(1)

    if (!existing) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [updated] = await db
      .update(projects)
      .set({ ...parsed.data, updatedAt: new Date() })
      .where(eq(projects.id, id))
      .returning()

    return updated
  })

  // Delete project
  app.delete('/api/projects/:id', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { id } = request.params as { id: string }

    const [existing] = await db
      .select({ id: projects.id })
      .from(projects)
      .where(and(eq(projects.id, id), eq(projects.userId, request.user!.id)))
      .limit(1)

    if (!existing) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    await db.delete(projects).where(eq(projects.id, id))

    return reply.status(204).send()
  })
}

import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import { eq, or } from 'drizzle-orm'
import crypto from 'crypto'
import { db } from '../db/index.js'
import { users } from '../db/schema/users.js'
import { sessions } from '../db/schema/sessions.js'
import { hashPassword, verifyPassword } from '../utils/password.js'
import { authMiddleware } from '../middleware/auth.js'
import { env } from '../env.js'

const registerSchema = z.object({
  username: z.string().min(3).max(32).regex(/^[a-zA-Z0-9_-]+$/),
  email: z.string().email().max(255),
  password: z.string().min(8).max(128),
})

const loginSchema = z.object({
  login: z.string().min(1),
  password: z.string().min(1),
})

const SESSION_DURATION_MS = 7 * 24 * 60 * 60 * 1000 // 7 days

function createSessionToken(): string {
  return crypto.randomBytes(48).toString('base64url')
}

function setCookieOptions() {
  return {
    path: '/' as const,
    httpOnly: true,
    secure: env.NODE_ENV === 'production' && env.COOKIE_DOMAIN !== 'localhost',
    sameSite: 'lax' as const,
    maxAge: SESSION_DURATION_MS / 1000,
  }
}

export async function authRoutes(app: FastifyInstance) {
  // Register
  app.post('/api/auth/register', async (request, reply) => {
    const parsed = registerSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const { username, email, password } = parsed.data

    // Check uniqueness
    const [existing] = await db
      .select({ id: users.id })
      .from(users)
      .where(or(eq(users.username, username), eq(users.email, email)))
      .limit(1)

    if (existing) {
      return reply.status(409).send({
        message: 'Username or email already taken',
        statusCode: 409,
      })
    }

    const passwordHash = await hashPassword(password)

    const [user] = await db
      .insert(users)
      .values({ username, email, passwordHash })
      .returning({
        id: users.id,
        username: users.username,
        email: users.email,
        role: users.role,
        createdAt: users.createdAt,
        updatedAt: users.updatedAt,
      })

    const token = createSessionToken()
    await db.insert(sessions).values({
      userId: user.id,
      token,
      expiresAt: new Date(Date.now() + SESSION_DURATION_MS),
    })

    reply.setCookie('session', token, setCookieOptions())

    return reply.status(201).send(user)
  })

  // Login
  app.post('/api/auth/login', async (request, reply) => {
    const parsed = loginSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: 'Invalid input',
        statusCode: 400,
      })
    }

    const { login, password } = parsed.data

    const [user] = await db
      .select()
      .from(users)
      .where(
        or(eq(users.email, login), eq(users.username, login)),
      )
      .limit(1)

    if (!user) {
      return reply.status(401).send({
        message: 'Invalid credentials',
        statusCode: 401,
      })
    }

    const valid = await verifyPassword(user.passwordHash, password)
    if (!valid) {
      return reply.status(401).send({
        message: 'Invalid credentials',
        statusCode: 401,
      })
    }

    const token = createSessionToken()
    await db.insert(sessions).values({
      userId: user.id,
      token,
      expiresAt: new Date(Date.now() + SESSION_DURATION_MS),
    })

    reply.setCookie('session', token, setCookieOptions())

    return {
      id: user.id,
      username: user.username,
      email: user.email,
      role: user.role,
      createdAt: user.createdAt,
      updatedAt: user.updatedAt,
    }
  })

  // Logout
  app.post('/api/auth/logout', { preHandler: [authMiddleware] }, async (request, reply) => {
    const token = request.cookies.session
    if (token) {
      await db.delete(sessions).where(eq(sessions.token, token))
    }
    reply.clearCookie('session', { path: '/' })
    return reply.status(204).send()
  })

  // Get current user
  app.get('/api/auth/me', { preHandler: [authMiddleware] }, async (request) => {
    return request.user
  })
}

import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import { eq, and, desc } from 'drizzle-orm'
import { db } from '../db/index.js'
import { projects } from '../db/schema/projects.js'
import { agentSessions } from '../db/schema/agent-sessions.js'
import { agentMessages } from '../db/schema/agent-messages.js'
import { agentLogs } from '../db/schema/agent-logs.js'
import { authMiddleware } from '../middleware/auth.js'

const sendMessageSchema = z.object({
  content: z.string().min(1).max(10000),
})

async function verifyProjectOwnership(userId: string, projectId: string) {
  const [project] = await db
    .select({ id: projects.id })
    .from(projects)
    .where(and(eq(projects.id, projectId), eq(projects.userId, userId)))
    .limit(1)
  return project
}

export async function agentRoutes(app: FastifyInstance) {
  // List agent sessions for a project
  app.get('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const sessions = await db
      .select()
      .from(agentSessions)
      .where(eq(agentSessions.projectId, projectId))
      .orderBy(desc(agentSessions.createdAt))

    return sessions
  })

  // Create a new agent session
  app.post('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .insert(agentSessions)
      .values({ projectId })
      .returning()

    return reply.status(201).send(session)
  })

  // Get a specific agent session with its messages
  app.get('/api/projects/:projectId/agent/sessions/:sessionId', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    const messages = await db
      .select()
      .from(agentMessages)
      .where(eq(agentMessages.sessionId, sessionId))
      .orderBy(agentMessages.createdAt)

    return { ...session, messages }
  })

  // Send a message to an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/messages', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }
    const parsed = sendMessageSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    const [message] = await db
      .insert(agentMessages)
      .values({
        sessionId,
        role: 'user',
        content: parsed.data.content,
      })
      .returning()

    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    return reply.status(201).send(message)
  })

  // Cancel an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/cancel', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    if (session.status !== 'running' && session.status !== 'idle') {
      return reply.status(400).send({ message: 'Session is not active', statusCode: 400 })
    }

    const [updated] = await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))
      .returning()

    await db.insert(agentLogs).values({
      sessionId,
      logType: 'status',
      message: 'Session cancelled by user',
    })

    return updated
  })

  // Get logs for a session
  app.get('/api/projects/:projectId/agent/sessions/:sessionId/logs', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const logs = await db
      .select()
      .from(agentLogs)
      .where(eq(agentLogs.sessionId, sessionId))
      .orderBy(agentLogs.createdAt)

    return logs
  })
}

