export class OpenCodeBridge implements BridgeInterface {
  name = 'opencode'
  private activeSessions = new Map<string, AbortController>()

  async initialize(): Promise<void> {
    // OpenCode runtime initialization will be implemented here
  }

  async executeTask(task: BridgeTask): Promise<BridgeResult> {
    // Placeholder: OpenCode execution will be wired up in the AI integration phase
    return {
      success: true,
      output: `OpenCode bridge received task for session ${task.sessionId}: "${task.prompt}"`,
    }
  }

  async streamResponse(task: BridgeTask, onEvent: (event: BridgeStreamEvent) => void): Promise<BridgeResult> {
    const controller = new AbortController()
    this.activeSessions.set(task.sessionId, controller)

    onEvent({
      type: 'status',
      content: 'OpenCode bridge connected',
      timestamp: new Date().toISOString(),
    })

    // Placeholder: streaming execution will be implemented in AI integration phase
    onEvent({
      type: 'complete',
      content: 'Task processing will be available after AI runtime integration',
      timestamp: new Date().toISOString(),
    })

    this.activeSessions.delete(task.sessionId)

    return {
      success: true,
      output: 'OpenCode bridge placeholder response',
    }
  }

  async cancelExecution(sessionId: string): Promise<void> {
    const controller = this.activeSessions.get(sessionId)
    if (controller) {
      controller.abort()
      this.activeSessions.delete(sessionId)
    }
  }

  isAvailable(): boolean {
    // Will check OpenCode runtime availability in AI integration phase
    return false
  }
}

